sys_script_include.script:
var RoleMatchCalculator = Class.create();

RoleMatchCalculator.prototype = {

    initialize: function() {},

    calculate: function(profileId) {

        // delete old matches
        var oldMatch = new GlideRecord(
            'x_1920001_careeros_role_match'
        );

        oldMatch.addQuery('profile', profileId);
        oldMatch.query();

        while (oldMatch.next())
            oldMatch.deleteRecord();

        // loop all roles
        var roleGR = new GlideRecord(
            'x_1920001_careeros_career_role'
        );

        roleGR.query();

        while (roleGR.next()) {

            var totalWeight = 0;
            var matchedWeight = 0;

            var roleSkills = {};

            var rs = new GlideRecord(
                'x_1920001_careeros_role_skill'
            );

            rs.addQuery('role', roleGR.sys_id);
            rs.query();

            while (rs.next()) {

                roleSkills[
                    rs.skills.toString()
                ] = parseInt(rs.weight,10);

                totalWeight += parseInt(
                    rs.weight,10
                );
            }

            var ps = new GlideRecord(
                'x_1920001_careeros_profile_skill'
            );

            ps.addQuery('profile', profileId);
            ps.query();

            while (ps.next()) {

                var skillId =
                    ps.skill.toString();

                if (roleSkills[skillId]) {

                    matchedWeight +=
                        roleSkills[skillId];
                }
            }

            var percentage = 0;

            if (totalWeight > 0) {

                percentage = Math.round(
                    (matchedWeight /
                     totalWeight) * 100
                );
            }

            var level = 'low';

            if (percentage >= 80)
                level = 'excellent';
            else if (percentage >= 60)
                level = 'high';
            else if (percentage >= 40)
                level = 'medium';

            var match = new GlideRecord(
                'x_1920001_careeros_role_match'
            );

            match.initialize();

            match.profile = profileId;
            match.role = roleGR.sys_id;
            match.match_percentage =
                percentage;

            match.match_level = level;

            match.recommendation =
                'Improve missing skills to increase match score';

            match.insert();
        }
    },

    type: 'RoleMatchCalculator'
};
